    {
        await sched.Start();
        JobKey jobKey = new JobKey("ExceptionPolicyRestartJob", "ExceptionPolicyRestartGroup");
        IJobDetail exceptionJob = JobBuilder.Create<ExceptionJob>()
            .WithIdentity(jobKey)
            .StoreDurably()
