using System.Collections.Specialized;
using Quartz;
using Quartz.Impl;
using Quartz.Listener;

await RunScenario("refire-then-success", failuresBeforeSuccess: 3, refireOnFailure: true, expectedAttempts: 4, expectedSecondExecutions: 1);
await RunScenario("terminal-failure", failuresBeforeSuccess: 1, refireOnFailure: false, expectedAttempts: 1, expectedSecondExecutions: 1);
await RunScenario("immediate-success", failuresBeforeSuccess: 0, refireOnFailure: false, expectedAttempts: 1, expectedSecondExecutions: 1);

static async Task RunScenario(string name, int failuresBeforeSuccess, bool refireOnFailure, int expectedAttempts, int expectedSecondExecutions)
{
    Console.WriteLine($"--- {name} ---");
    var props = new NameValueCollection
    {
        ["quartz.scheduler.instanceName"] = $"RefireChainRepro-{name}",
        ["quartz.threadPool.threadCount"] = "1"
    };

    var scheduler = await new StdSchedulerFactory(props).GetScheduler();
    var chain = new JobChainingJobListener("chain");
    scheduler.ListenerManager.AddJobListener(chain);

    var firstKey = new JobKey($"first-{name}", "g");
    var secondKey = new JobKey($"second-{name}", "g");
    chain.AddJobChainLink(firstKey, secondKey);

    FailThenSucceedJob.Attempts = 0;
    FailThenSucceedJob.FailuresBeforeSuccess = failuresBeforeSuccess;
    FailThenSucceedJob.RefireOnFailure = refireOnFailure;
    CountingJob.Executions = 0;
    CountingJob.Completion = new TaskCompletionSource(TaskCreationOptions.RunContinuationsAsynchronously);

    var first = JobBuilder.Create<FailThenSucceedJob>().WithIdentity(firstKey).Build();
    var second = JobBuilder.Create<CountingJob>().WithIdentity(secondKey).StoreDurably().Build();
    var trigger = TriggerBuilder.Create().WithIdentity($"first-trigger-{name}", "g").StartNow().Build();

    await scheduler.ScheduleJob(first, trigger);
    await scheduler.AddJob(second, true);
    await scheduler.Start();

    var completed = await Task.WhenAny(CountingJob.Completion.Task, Task.Delay(TimeSpan.FromSeconds(10)));
    await Task.Delay(500);
    Console.WriteLine($"first attempts={FailThenSucceedJob.Attempts}, second executions={CountingJob.Executions}, completed={completed == CountingJob.Completion.Task}");
    await scheduler.Shutdown(waitForJobsToComplete: true);

    if (FailThenSucceedJob.Attempts != expectedAttempts || CountingJob.Executions != expectedSecondExecutions)
    {
        Console.Error.WriteLine($"Unexpected result for {name}. Expected attempts={expectedAttempts}, second={expectedSecondExecutions}.");
        Environment.Exit(1);
    }
}

public class FailThenSucceedJob : IJob
{
    public static int Attempts;
    public static int FailuresBeforeSuccess;
    public static bool RefireOnFailure;

    public ValueTask Execute(IJobExecutionContext context)
    {
        var attempt = Interlocked.Increment(ref Attempts);
        Console.WriteLine($"first attempt {attempt}, refireCount={context.RefireCount}");
        if (attempt <= FailuresBeforeSuccess)
        {
            throw new JobExecutionException("planned failure") { RefireImmediately = RefireOnFailure };
        }

        return default;
    }
}

public class CountingJob : IJob
{
    public static int Executions;
    public static TaskCompletionSource Completion = null!;

    public ValueTask Execute(IJobExecutionContext context)
    {
        var executions = Interlocked.Increment(ref Executions);
        Console.WriteLine($"second execution {executions}");
        Completion.TrySetResult();
        return default;
    }
}
